mapper.select:
SELECT sa.application_id, sa.student_id, sa.award_id, sa.application_time, sa.status, sa.teacher_approval_status, sa.teacher_approval_time, sa.teacher_approval_comments, sa.admin_approval_status, sa.admin_approval_time, sa.admin_approval_comments, sa.created_at, sa.updated_at, a.award_name, a.award_level, a.award_type, a.description AS award_description, a.requirement, a.quota, a.start_time, a.end_time, a.status AS award_status, a.current_status FROM student_award_applications sa LEFT JOIN awards a ON sa.award_id = a.id WHERE sa.student_id = #{studentId}
AND a.award_name LIKE CONCAT('%', #{awardName}, '%')
AND sa.status = #{status}
ORDER BY sa.application_time DESC
